import React, { useState, useRef, useEffect } from 'react';
import API from '../utils/api';

const INTERVIEW_TYPES = [
  { id: 'product', label: '🏢 Product Company', desc: 'Google, Microsoft, Amazon style', color: '#6366f1' },
  { id: 'service', label: '🏗️ Service Company', desc: 'TCS, Infosys, Wipro style', color: '#10b981' },
  { id: 'startup', label: '🚀 Startup', desc: 'Fast-paced, full-stack focus', color: '#f59e0b' },
  { id: 'banking', label: '🏦 Banking / Finance', desc: 'BFSI sector focus', color: '#3b82f6' },
];

const ROUNDS = ['HR Round', 'Technical Round', 'Managerial Round'];

export default function MockInterview() {
  const [stage, setStage] = useState('setup'); // setup | interview | result
  const [interviewType, setInterviewType] = useState(null);
  const [round, setRound] = useState('HR Round');
  const [messages, setMessages] = useState([]);
  const [userInput, setUserInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [questionCount, setQuestionCount] = useState(0);
  const [scores, setScores] = useState([]);
  const [finalResult, setFinalResult] = useState(null);
  const [interviewDone, setInterviewDone] = useState(false);
  const chatEndRef = useRef(null);
  const MAX_QUESTIONS = 5;

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const startInterview = async () => {
    if (!interviewType) return;
    setStage('interview');
    setLoading(true);
    setMessages([]);
    setQuestionCount(0);
    setScores([]);
    setInterviewDone(false);

    const systemPrompt = `You are a professional interviewer at a ${interviewType.label.replace(/[^a-zA-Z ]/g,'').trim()} company conducting a ${round} for a fresher software engineer position.

STRICT RULES:
1. Ask ONE question at a time only
2. After the candidate answers, give brief feedback (2-3 lines) on their answer mentioning what was good and what could improve
3. Then give a score for that answer from 1-10 in this EXACT format: [SCORE:X] where X is the number
4. Then ask the next question
5. After exactly ${MAX_QUESTIONS} questions, say "INTERVIEW_COMPLETE" and give an overall summary

Start by greeting the candidate warmly and asking the first question immediately. Keep questions relevant to ${round} for a ${interviewType.label} company.`;

    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 1000,
          system: systemPrompt,
          messages: [{ role: 'user', content: 'Start the interview.' }]
        })
      });
      const data = await res.json();
      const text = data.content?.[0]?.text || 'Hello! Welcome to your mock interview. Tell me about yourself.';
      setMessages([{ role: 'ai', text, type: 'question' }]);
      setQuestionCount(1);
    } catch (e) {
      setMessages([{ role: 'ai', text: "Welcome to your mock interview! Let's begin. Tell me about yourself and your background.", type: 'question' }]);
      setQuestionCount(1);
    }
    setLoading(false);
  };

  const sendAnswer = async () => {
    if (!userInput.trim() || loading || interviewDone) return;
    const answer = userInput.trim();
    setUserInput('');
    const newMessages = [...messages, { role: 'user', text: answer }];
    setMessages(newMessages);
    setLoading(true);

    const conversationHistory = newMessages.map(m => ({
      role: m.role === 'ai' ? 'assistant' : 'user',
      content: m.text
    }));

    const systemPrompt = `You are a professional interviewer at a ${interviewType.label.replace(/[^a-zA-Z ]/g,'').trim()} company conducting a ${round} for a fresher software engineer.

STRICT RULES:
1. Give brief feedback on the candidate's answer (2-3 lines max)
2. Always include a score in EXACT format: [SCORE:X] where X is 1-10
3. If this was question ${questionCount} of ${MAX_QUESTIONS}, and ${questionCount} >= ${MAX_QUESTIONS}, write "INTERVIEW_COMPLETE" then give a 3-line overall performance summary
4. Otherwise ask the next question
5. Keep it conversational and encouraging`;

    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 800,
          system: systemPrompt,
          messages: conversationHistory
        })
      });
      const data = await res.json();
      const text = data.content?.[0]?.text || 'Good answer! Let me ask you the next question.';

      // Extract score
      const scoreMatch = text.match(/\[SCORE:(\d+)\]/);
      if (scoreMatch) {
        const sc = parseInt(scoreMatch[1]);
        setScores(prev => [...prev, sc]);
      }

      const isDone = text.includes('INTERVIEW_COMPLETE');
      if (isDone) {
        setInterviewDone(true);
        const allScores = [...scores, scoreMatch ? parseInt(scoreMatch[1]) : 6];
        const avg = allScores.length ? Math.round(allScores.reduce((a, b) => a + b, 0) / allScores.length) : 6;
        setFinalResult({ avg, scores: allScores, summary: text.replace('INTERVIEW_COMPLETE', '').replace(/\[SCORE:\d+\]/g, '').trim() });
      }

      setMessages(prev => [...prev, { role: 'ai', text: text.replace(/\[SCORE:\d+\]/g, '').replace('INTERVIEW_COMPLETE', '').trim(), type: isDone ? 'complete' : 'feedback', score: scoreMatch ? parseInt(scoreMatch[1]) : null }]);
      if (!isDone) setQuestionCount(prev => prev + 1);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'ai', text: 'Good effort! Keep going with the next question.', type: 'feedback' }]);
    }
    setLoading(false);
  };

  const getScoreColor = (s) => s >= 8 ? '#10b981' : s >= 6 ? '#f59e0b' : '#ef4444';
  const getScoreLabel = (s) => s >= 8 ? 'Excellent' : s >= 6 ? 'Good' : s >= 4 ? 'Average' : 'Needs Work';

  if (stage === 'setup') return (
    <div className="content-area fade-in">
      <h1 className="section-title">🤖 AI Mock Interview</h1>
      <p className="section-sub">Practice with an AI interviewer and get instant feedback on every answer</p>

      <div className="card" style={{ maxWidth: 700, margin: '0 auto' }}>
        <h3 style={{ fontFamily: 'Space Grotesk', marginBottom: 6 }}>Select Company Type</h3>
        <p style={{ color: 'var(--text2)', fontSize: 13, marginBottom: 20 }}>Each type has different question styles and expectations</p>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 24 }}>
          {INTERVIEW_TYPES.map(t => (
            <div key={t.id} onClick={() => setInterviewType(t)}
              style={{ padding: '16px 18px', borderRadius: 12, cursor: 'pointer', border: `2px solid ${interviewType?.id === t.id ? t.color : 'var(--border)'}`, background: interviewType?.id === t.id ? `${t.color}15` : 'var(--bg)', transition: 'all 0.2s' }}>
              <div style={{ fontSize: 18, fontWeight: 700, marginBottom: 4 }}>{t.label}</div>
              <div style={{ fontSize: 12, color: 'var(--text3)' }}>{t.desc}</div>
              {interviewType?.id === t.id && <div style={{ marginTop: 8, fontSize: 11, color: t.color, fontWeight: 700 }}>✓ Selected</div>}
            </div>
          ))}
        </div>

        <h3 style={{ fontFamily: 'Space Grotesk', marginBottom: 12 }}>Select Round</h3>
        <div style={{ display: 'flex', gap: 10, marginBottom: 28 }}>
          {ROUNDS.map(r => (
            <button key={r} onClick={() => setRound(r)}
              style={{ flex: 1, padding: '10px 8px', borderRadius: 10, fontSize: 12, fontWeight: 600, cursor: 'pointer', border: `1px solid ${round === r ? 'var(--accent)' : 'var(--border)'}`, background: round === r ? 'rgba(99,102,241,0.15)' : 'var(--bg)', color: round === r ? 'var(--accent)' : 'var(--text2)', fontFamily: 'Outfit, sans-serif' }}>
              {r}
            </button>
          ))}
        </div>

        <div style={{ background: 'var(--bg2)', borderRadius: 12, padding: 16, marginBottom: 24, fontSize: 13 }}>
          <div style={{ fontWeight: 700, marginBottom: 8, color: 'var(--text)' }}>📋 How it works:</div>
          <div style={{ color: 'var(--text2)', lineHeight: 1.8 }}>
            • AI asks you <strong>{MAX_QUESTIONS} questions</strong> one by one<br />
            • You type your answers naturally<br />
            • AI gives <strong>instant feedback</strong> after each answer<br />
            • Get a <strong>final score and report</strong> at the end
          </div>
        </div>

        <button className="btn btn-primary" style={{ width: '100%', padding: 14, fontSize: 16 }}
          onClick={startInterview} disabled={!interviewType}>
          🚀 Start Mock Interview
        </button>
      </div>
    </div>
  );

  return (
    <div className="content-area fade-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <div>
          <h1 className="section-title">🤖 AI Mock Interview</h1>
          <p className="section-sub">{interviewType?.label} — {round} — Question {Math.min(questionCount, MAX_QUESTIONS)}/{MAX_QUESTIONS}</p>
        </div>
        <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
          {scores.length > 0 && (
            <div style={{ background: 'var(--card)', border: '1px solid var(--border)', borderRadius: 10, padding: '8px 16px', textAlign: 'center' }}>
              <div style={{ fontSize: 18, fontWeight: 800, color: 'var(--accent)' }}>{Math.round(scores.reduce((a,b)=>a+b,0)/scores.length)}/10</div>
              <div style={{ fontSize: 10, color: 'var(--text3)' }}>Avg Score</div>
            </div>
          )}
          <button className="btn btn-secondary" onClick={() => setStage('setup')}>← Change Setup</button>
        </div>
      </div>

      {/* Progress */}
      <div style={{ marginBottom: 20 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12, color: 'var(--text3)', marginBottom: 6 }}>
          <span>Interview Progress</span>
          <span>{Math.min(questionCount, MAX_QUESTIONS)}/{MAX_QUESTIONS} questions</span>
        </div>
        <div style={{ height: 6, background: 'var(--bg2)', borderRadius: 10 }}>
          <div style={{ height: '100%', borderRadius: 10, background: 'linear-gradient(90deg, var(--accent), #8b5cf6)', width: `${(Math.min(questionCount, MAX_QUESTIONS) / MAX_QUESTIONS) * 100}%`, transition: 'width 0.5s' }} />
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '3fr 1fr', gap: 20, alignItems: 'start' }}>
        {/* Chat window */}
        <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
          <div style={{ height: 420, overflowY: 'auto', padding: 20, display: 'flex', flexDirection: 'column', gap: 14 }}>
            {messages.map((m, i) => (
              <div key={i} style={{ display: 'flex', gap: 10, flexDirection: m.role === 'user' ? 'row-reverse' : 'row' }}>
                <div style={{ width: 36, height: 36, borderRadius: '50%', background: m.role === 'ai' ? 'var(--accent)' : 'var(--bg2)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 16, flexShrink: 0 }}>
                  {m.role === 'ai' ? '🤖' : '👤'}
                </div>
                <div style={{ maxWidth: '75%' }}>
                  <div style={{ padding: '12px 16px', borderRadius: m.role === 'user' ? '16px 4px 16px 16px' : '4px 16px 16px 16px', background: m.role === 'user' ? 'var(--accent)' : 'var(--bg2)', color: m.role === 'user' ? 'white' : 'var(--text)', fontSize: 14, lineHeight: 1.6 }}>
                    {m.text}
                  </div>
                  {m.score && (
                    <div style={{ marginTop: 6, display: 'flex', gap: 6, alignItems: 'center', justifyContent: m.role === 'user' ? 'flex-end' : 'flex-start' }}>
                      <span style={{ fontSize: 11, fontWeight: 700, color: getScoreColor(m.score), background: `${getScoreColor(m.score)}22`, padding: '3px 10px', borderRadius: 20 }}>
                        Answer Score: {m.score}/10 — {getScoreLabel(m.score)}
                      </span>
                    </div>
                  )}
                </div>
              </div>
            ))}
            {loading && (
              <div style={{ display: 'flex', gap: 10 }}>
                <div style={{ width: 36, height: 36, borderRadius: '50%', background: 'var(--accent)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>🤖</div>
                <div style={{ padding: '12px 16px', borderRadius: '4px 16px 16px 16px', background: 'var(--bg2)', display: 'flex', gap: 6, alignItems: 'center' }}>
                  {[0,1,2].map(i => <div key={i} style={{ width: 8, height: 8, borderRadius: '50%', background: 'var(--accent)', animation: `bounce 1s ease-in-out ${i*0.2}s infinite` }} />)}
                </div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          {!interviewDone ? (
            <div style={{ padding: '14px 16px', borderTop: '1px solid var(--border)', display: 'flex', gap: 10 }}>
              <textarea
                value={userInput}
                onChange={e => setUserInput(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendAnswer(); } }}
                placeholder="Type your answer here... (Press Enter to send, Shift+Enter for new line)"
                rows={2}
                disabled={loading || interviewDone}
                style={{ flex: 1, background: 'var(--bg)', color: 'var(--text)', border: '1px solid var(--border)', borderRadius: 10, padding: '10px 14px', fontSize: 13, fontFamily: 'Outfit, sans-serif', resize: 'none', outline: 'none' }}
              />
              <button onClick={sendAnswer} disabled={loading || !userInput.trim() || interviewDone}
                style={{ padding: '0 20px', borderRadius: 10, border: 'none', background: 'var(--accent)', color: 'white', fontSize: 18, cursor: 'pointer', opacity: loading || !userInput.trim() ? 0.5 : 1 }}>
                ➤
              </button>
            </div>
          ) : finalResult && (
            <div style={{ padding: 20, borderTop: '1px solid var(--border)', textAlign: 'center' }}>
              <div style={{ fontSize: 32, marginBottom: 8 }}>{finalResult.avg >= 8 ? '🏆' : finalResult.avg >= 6 ? '🎯' : '📚'}</div>
              <div style={{ fontSize: 28, fontWeight: 800, color: getScoreColor(finalResult.avg), marginBottom: 4 }}>{finalResult.avg}/10 Overall</div>
              <p style={{ color: 'var(--text2)', fontSize: 13, marginBottom: 16 }}>{finalResult.avg >= 8 ? 'Outstanding performance!' : finalResult.avg >= 6 ? 'Good job! Keep practicing.' : 'More practice will help.'}</p>
              <button className="btn btn-primary" onClick={() => setStage('setup')}>🔄 Start New Interview</button>
            </div>
          )}
        </div>

        {/* Score panel */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          <div className="card">
            <div style={{ fontWeight: 700, fontSize: 13, marginBottom: 12, color: 'var(--text2)' }}>📊 Score Card</div>
            {scores.length === 0 ? (
              <p style={{ fontSize: 12, color: 'var(--text3)', textAlign: 'center', padding: '20px 0' }}>Scores will appear after each answer</p>
            ) : (
              scores.map((s, i) => (
                <div key={i} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
                  <span style={{ fontSize: 12, color: 'var(--text2)' }}>Q{i + 1}</span>
                  <div style={{ flex: 1, height: 6, background: 'var(--bg2)', borderRadius: 10, margin: '0 8px' }}>
                    <div style={{ height: '100%', borderRadius: 10, background: getScoreColor(s), width: `${s * 10}%` }} />
                  </div>
                  <span style={{ fontSize: 12, fontWeight: 700, color: getScoreColor(s) }}>{s}/10</span>
                </div>
              ))
            )}
          </div>

          <div className="card">
